            ?.Value;

        string lastName = req.GetQueryNameValuePairs()
            .FirstOrDefault(q => string.Compare(q.Key, "lastName", true) == 0)
            ?.Value;

        // sql query
        SqlConnection conn = new SqlConnection();
        conn.ConnectionString = connectionString;
        var queryString = "select * from dbo.[Customer] where ";


        if (!string.IsNullOrEmpty(firstName))
        {
            if (string.IsNullOrEmpty(lastName))
                throw new Exception("You need to provide a lastName!");

            queryString += "[FirstName] LIKE '%" + firstName + "%' AND [LastName] LIKE '%" + lastName + "%'";
        }

        conn.Open();
        var command = new SqlCommand(queryString, connection);
        var reader = command.ExecuteReader(); // execute sql query
        log.Info($"Query is: {command}");
    }

